const body = $input.first().json.body;
const events = body?.events || [];
if (events.length === 0) return [{ json: { valid: false, reason: 'No events' } }];
const event = events[0];
const userId = event.source?.userId || '';
const replyToken = event.message?.type === 'text' ? event.replyToken : '';
const messageText = event.message?.text || '';

const EMPLOYEE_MAP = {
  "Uc1e1e958fb952752c3d34628a17585a1": "野添優",
  "Uf662ab811bee1780522da7356c0efb9e": "丸田翔吾",
  "Ua9a65f01bf77adcc825b05811950480d": "源地健史",
  "U65929805c0527b9f75b5276fc250c304": "服部秀一",
  "Uadfb98160637cc7f96bccb051c4a51f9": "梶原通信",
  "Uf97fd2e35007f697094a9520e1baeafd": "井本貴士",
  "REPLACE_LLS_USERID":               "LLS電気",
  "REPLACE_TRUST_USERID":             "株式会社トラストテクノス",
  "REPLACE_RISE_USERID":              "株式会社RISE"
};

const employeeName = EMPLOYEE_MAP[userId];
if (!employeeName) return [{ json: { valid: false, reason: '未登録ユーザー', userId, replyToken } }];

const msgLower = messageText.toLowerCase();
const messageType = (msgLower.includes('請求') || msgLower.includes('集計')) ? 'billing_query' : 'daily_report';

return [{ json: { valid: true, userId, employeeName, messageText, replyToken, messageType } }];

const data = $input.first().json;
const claudeText = data.claudeResponse || '';
const lineToken = 'Bearer YOUR_LINE_TOKEN';

const sendLineError = async (msg) => {
  if (data.replyToken) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.line.me/v2/bot/message/reply',
        headers: { 'Authorization': lineToken, 'Content-Type': 'application/json' },
        body: { replyToken: data.replyToken, messages: [{ type: 'text', text: msg }] },
        json: true
      });
    } catch(e) {}
  }
};

let parsed;
try {
  const match = claudeText.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('JSONが見つかりません');
  parsed = JSON.parse(match[0]);
} catch(e) {
  await sendLineError(`日報のフォーマットが認識できませんでした。\n正しいフォーマットで送信してください。`);
  throw new Error('日報フォーマットエラー: ' + e.message);
}

if (!parsed.date || !parsed.sites || parsed.sites.length === 0) {
  await sendLineError(`日付または現場情報が記載されていません。\n確認してもう一度送信してください。`);
  throw new Error('日報バリデーションエラー');
}

// ========= 正規化関数 =========
const toHalfWidth = (s) => (s || '').toString().replace(/[Ａ-Ｚａ-ｚ０-９]/g,
  c => String.fromCharCode(c.charCodeAt(0) - 0xFEE0))
  .replace(/[‐－―ー−]/g, '-').replace(/[　]/g, ' ');

const normalizeTime = (t) => {
  if (!t) return '';
  const s = toHalfWidth(t).trim();
  // 8:30 / 8.30 / 8時30分 / 8 30 / 0830
  let m = s.match(/^(\d{1,2})[:\.時\s](\d{1,2})/);
  if (m) return `${String(m[1]).padStart(2,'0')}:${String(m[2]).padStart(2,'0')}`;
  m = s.match(/^(\d{1,2})半/); // 8半 → 08:30
  if (m) return `${String(m[1]).padStart(2,'0')}:30`;
  m = s.match(/^(\d{1,2})$/); // 8 → 08:00
  if (m) return `${String(m[1]).padStart(2,'0')}:00`;
  m = s.match(/^(\d{2})(\d{2})$/); // 0830
  if (m) return `${m[1]}:${m[2]}`;
  return s;
};

const COMPANY_ALIASES = {
  '平成': '平成システム', 'ヘイセイ': '平成システム',
  'トラスト': 'トラストテクノス',
  'オーク': 'オークコミュニケーション', 'オークコム': 'オークコミュニケーション',
  '千里': '千里スカイハイツ管理組合',
  '港': '港振興業', '港振': '港振興業', 'コウシン': '港振興業', 'コウシンギョウ': '港振興業',
  '梶原': '梶原通信',
  'ジースタイル': 'G-STYLE', 'Gスタイル': 'G-STYLE', 'G-STYLE': 'G-STYLE',
  'FGE': 'FGE', 'mtr': 'mtr', 'MTR': 'mtr',
  'ライズ': 'ライズ', '菊次': '菊次', 'ページ': 'ページ',
  'LLS電気': 'LLS電気', 'LLS': 'LLS電気'
};

const resolveCompany = (name) => {
  const n = toHalfWidth(name).trim();
  if (COMPANY_ALIASES[n]) return COMPANY_ALIASES[n];
  for (const [alias, full] of Object.entries(COMPANY_ALIASES)) {
    if (n.includes(alias)) return full;
  }
  return n;
};

const normalizeKubun = (k) => {
  const s = (k || '').toString().trim();
  if (s.includes('夜')) return '夜勤';
  return '昼勤';
};

// ========= 各現場を正規化 =========
const sites = parsed.sites.map(site => ({
  ...site,
  companyName: resolveCompany(site.companyName || ''),
  propertyName: toHalfWidth(site.propertyName || ''),
  kubun: normalizeKubun(site.kubun),
  startTime: normalizeTime(site.startTime),
  endTime: normalizeTime(site.endTime),
  breakMinutes: parseInt(site.breakMinutes) || 0,
  highwayFee: parseInt(site.highwayFee) || 0,
  distance: parseFloat(site.distance) || 0,
  parkingFee: parseInt(site.parkingFee) || 0,
  materialCost: parseInt(site.materialCost) || 0
}));

const dateParts = parsed.date.split('/');
const fileYear  = parseInt(dateParts[0]);
const fileMonth = parseInt(dateParts[1]);
const fileName  = `稼働表_${fileYear}年${String(fileMonth).padStart(2,'0')}月`;

return [{ json: { ...data, parsedDate: parsed.date, sites, fileName, fileYear, fileMonth } }];

const data = $input.first().json;
const siteList = (data.sites || []).map(s =>
  `・${s.companyName} ${s.propertyName || ''} ${s.kubun || ''} ${s.startTime || ''}〜${s.endTime || ''} (${s.workHours || ''})`
).join('\n');
const replyMessage = `✅ 日報を記録しました\n日付: ${data.parsedDate}\n担当: ${data.employeeName}\n${siteList}\nお疲れ様でした`.trim();
return [{ json: { ...data, replyMessage } }];

const lineToken = 'Bearer YOUR_LINE_TOKEN';
const data = $input.first().json;
if (data.replyToken) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.line.me/v2/bot/message/reply',
    headers: { 'Authorization': lineToken, 'Content-Type': 'application/json' },
    body: { replyToken: data.replyToken, messages: [{ type: 'text', text: data.replyMessage }] },
    json: true
  });
}
return [{ json: { done: true } }];

const data = $input.first().json;

const normalize = (name) =>
  (name || '').replace(/株式会社|有限会社|合同会社|一般社団法人|一般財団法人/g, '').trim();

const BILLING_COMPANIES = [
  '港振興業', 'トラストテクノス', '平成システム', 'FGE',
  'mtr', 'オークコミュニケーション', 'ライズ',
  '千里スカイハイツ管理組合', '菊次', 'ページ', 'G-STYLE', '梶原通信', 'LLS電気'
];
const CLOSING_20 = ['平成システム'];
const COMPANY_ALIASES = {
  '平成': '平成システム', 'トラスト': 'トラストテクノス',
  'オーク': 'オークコミュニケーション', '千里': '千里スカイハイツ管理組合',
  '港': '港振興業', '港振': '港振興業', 'コウシン': '港振興業',
  '梶原': '梶原通信', 'ジースタイル': 'G-STYLE', 'Gスタイル': 'G-STYLE'
};

const resolveAlias = (name) => {
  for (const [alias, full] of Object.entries(COMPANY_ALIASES)) {
    if (normalize(name).includes(normalize(alias))) return full;
  }
  return name;
};

const parts = (data.parsedDate || '').split('/');
const year  = parseInt(parts[0]) || 0;
const month = parseInt(parts[1]) || 0;
const day   = parseInt(parts[2]) || 0;

const billingSites = (data.sites || []).filter(site => {
  const resolved = resolveAlias(site.companyName);
  const norm = normalize(resolved);
  return BILLING_COMPANIES.some(c => norm.includes(normalize(c)) || normalize(c).includes(norm));
});

if (billingSites.length === 0) return [];

const groups = {};
for (const site of billingSites) {
  const resolved = resolveAlias(site.companyName);
  const norm = normalize(resolved);
  const is20 = CLOSING_20.some(c => norm.includes(normalize(c)) || normalize(c).includes(norm));
  let bYear = year, bMonth = month;
  if (is20 && day >= 21) {
    bMonth = month + 1;
    if (bMonth > 12) { bMonth = 1; bYear = year + 1; }
  }
  const key = `${bYear}-${bMonth}`;
  if (!groups[key]) groups[key] = { bYear, bMonth, sites: [] };
  groups[key].sites.push({ ...site, companyName: resolved });
}

const results = [];
for (const group of Object.values(groups)) {
  const billingFileName = `請求集計_${group.bYear}年${String(group.bMonth).padStart(2,'0')}月`;
  results.push({ json: { ...data, billingYear: group.bYear, billingMonth: group.bMonth, billingFileName, billingSites: group.sites } });
}
return results;

const lineToken = 'Bearer YOUR_LINE_TOKEN';
const NOZOE_ID = 'Uc1e1e958fb952752c3d34628a17585a1';
const data = $input.first().json;

const companyNames = (data.billingSites || []).map(s => s.companyName).join('、');
const msg = data.billingFileName
  ? `請求集計を更新しました\nファイル: ${data.billingFileName}\n担当: ${data.employeeName}\n対象会社: ${companyNames}`
  : '請求集計を更新しました';

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.line.me/v2/bot/message/push',
  headers: { 'Authorization': lineToken, 'Content-Type': 'application/json' },
  body: { to: NOZOE_ID, messages: [{ type: 'text', text: msg }] },
  json: true
});
return [{ json: { done: true } }];

const data = $input.first().json;
const spreadsheetId = (data.files || [])[0]?.id;
if (!spreadsheetId) throw new Error(`スプレッドシートが見つかりません: ${data.fileName}`);
const sheetName = data.employeeName;
const readUrl = `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/${encodeURIComponent(sheetName)}!A:A`;
return [{ json: { ...data, spreadsheetId, readUrl } }];

const data = $input.first().json;
const existingValues = data.values || [];
const parsedDate = data.parsedDate;
const lineToken = 'Bearer YOUR_LINE_TOKEN';

const dataRows = existingValues.slice(2);
const normalize = (d) => (d || '').toString().replace(/[\-\.]/g, '/').trim();
const isDuplicate = dataRows.some(row => normalize(row[0]) === normalize(parsedDate));

if (isDuplicate) {
  if (data.replyToken) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.line.me/v2/bot/message/reply',
        headers: { 'Authorization': lineToken, 'Content-Type': 'application/json' },
        body: { replyToken: data.replyToken, messages: [{ type: 'text', text: `${parsedDate}の日報はすでに送信済みです。\n重複データは記録されませんでした。` }] },
        json: true
      });
    } catch(e) {}
  }
  throw new Error(`重複: ${parsedDate}の日報は送信済み`);
}

return [{ json: { ...data } }];

const data = $input.first().json;
const files = data.files || [];

const BILLING_COMPANIES = [
  '港振興業', 'トラストテクノス', '平成システム', 'FGE',
  'mtr', 'オークコミュニケーション', 'ライズ',
  '千里スカイハイツ管理組合', '菊次', 'ページ', 'G-STYLE', '梶原通信', 'LLS電気'
];
const HEADERS = ['日付', '区分', '物件名', '人員名', '人員数', '高速(円)', '距離(km)', '駐車場(円)', '資材費(円)'];

let spreadsheetId;

if (files.length > 0) {
  spreadsheetId = files[0].id;
} else {
  // 新規スプレッドシート作成（12社分のシートを同時に作る）
  const createRes = await this.helpers.httpRequestWithAuthentication.call(
    this,
    'googleSheetsOAuth2Api',
    {
      method: 'POST',
      url: 'https://sheets.googleapis.com/v4/spreadsheets',
      body: {
        properties: { title: data.billingFileName },
        sheets: BILLING_COMPANIES.map((name, i) => ({
          properties: { sheetId: i + 1, title: name, index: i }
        }))
      },
      json: true
    }
  );
  spreadsheetId = createRes.spreadsheetId;

  // 指定フォルダに移動
  await this.helpers.httpRequestWithAuthentication.call(
    this, 'googleSheetsOAuth2Api', {
      method: 'PATCH',
      url: `https://www.googleapis.com/drive/v3/files/${spreadsheetId}?addParents=1_hE52JdvZ-Nyl-lUyKWzhFN6Lqphp9yA&removeParents=root&fields=id,parents`,
      json: true
    });

  // 各シートにヘッダー行を追加（一括 batchUpdate）
  const valueRanges = BILLING_COMPANIES.map(name => ({
    range: `${name}!A1`,
    majorDimension: 'ROWS',
    values: [HEADERS]
  }));

  await this.helpers.httpRequestWithAuthentication.call(
    this,
    'googleSheetsOAuth2Api',
    {
      method: 'POST',
      url: `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values:batchUpdate`,
      body: {
        valueInputOption: 'USER_ENTERED',
        data: valueRanges
      },
      json: true
    }
  );

  // デフォルトで作成される 'Sheet1' を削除（任意）
  // 12社シートを作成済みなのでSheet1は不要だが、createでsheets指定したので元々作られない
}

return [{ json: { ...data, billingSpreadsheetId: spreadsheetId } }];

const data = $input.first().json;
const spreadsheetId = data.spreadsheetId;
const sheetName = data.employeeName;
if (!spreadsheetId) throw new Error('稼働表スプレッドシートIDが未設定');
if (!sheetName) throw new Error('シート名（employeeName）が未設定');

const MULTI_PERSON = ['梶原通信', 'LLS電気', '株式会社トラストテクノス', '株式会社RISE'];
const isMulti = MULTI_PERSON.includes(sheetName);

const sites = data.sites || [];
if (sites.length === 0) throw new Error('書き込むデータがありません');

const url = `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/${encodeURIComponent(sheetName)}:append?valueInputOption=USER_ENTERED&insertDataOption=INSERT_ROWS`;

const writtenRows = [];
for (const site of sites) {
  const staffCount = site.staffCount && site.staffCount > 0 ? site.staffCount : 1;
  const rowValues = isMulti ? [
    data.parsedDate,
    site.kubun || '',
    site.companyName || '',
    site.propertyName || '',
    site.startTime || '',
    site.endTime || '',
    site.breakMinutes || 0,
    site.workHours || '',
    site.workContent || '',
    staffCount,
    site.staffNames || '',
    site.highwayFee || 0,
    site.distance || 0,
    site.parkingFee || 0,
    site.materialCost || 0
  ] : [
    data.parsedDate,
    site.kubun || '',
    site.companyName || '',
    site.propertyName || '',
    site.startTime || '',
    site.endTime || '',
    site.breakMinutes || 0,
    site.workHours || '',
    site.workContent || '',
    site.highwayFee || 0,
    site.distance || 0,
    site.parkingFee || 0,
    site.materialCost || 0
  ];
  await this.helpers.httpRequestWithAuthentication.call(
    this,
    'googleSheetsOAuth2Api',
    { method: 'POST', url, body: { values: [rowValues] }, json: true }
  );
  writtenRows.push(rowValues);
}

// 書き込み後：開始時刻・終了時刻列(E/F)を時刻書式に設定（毎回でも害なし）
try {
  const meta = await this.helpers.httpRequestWithAuthentication.call(
    this, 'googleSheetsOAuth2Api', {
      method: 'GET',
      url: `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}?fields=sheets.properties`,
      json: true
    });
  const sheet = (meta.sheets || []).find(s => s.properties.title === sheetName);
  if (sheet) {
    const sheetId = sheet.properties.sheetId;
    const requests = [4, 5].map(colIdx => ({
      repeatCell: {
        range: { sheetId, startColumnIndex: colIdx, endColumnIndex: colIdx + 1 },
        cell: { userEnteredFormat: { numberFormat: { type: 'TIME', pattern: 'h:mm' } } },
        fields: 'userEnteredFormat.numberFormat'
      }
    }));
    await this.helpers.httpRequestWithAuthentication.call(
      this, 'googleSheetsOAuth2Api', {
        method: 'POST',
        url: `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}:batchUpdate`,
        body: { requests },
        json: true
      });
  }
} catch(e) {}

return [{ json: { ...data, writtenRows, writeSuccess: true } }];

const data = $input.first().json;
const spreadsheetId = data.billingSpreadsheetId;
if (!spreadsheetId) throw new Error('請求集計スプレッドシートIDが未設定');

const normalize = (name) =>
  (name || '').replace(/株式会社|有限会社|合同会社|一般社団法人|一般財団法人/g, '').trim();

const billingSites = data.billingSites || [];
if (billingSites.length === 0) return [{ json: { ...data, billingWritten: 0 } }];

let written = 0;
for (const site of billingSites) {
  const sheetName = normalize(site.companyName);
  const url = `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/${encodeURIComponent(sheetName)}:append?valueInputOption=USER_ENTERED&insertDataOption=INSERT_ROWS`;
  const staffCount = site.staffCount && site.staffCount > 0 ? site.staffCount : 1;
  const rowValues = [
    data.parsedDate,
    site.kubun || '',
    site.propertyName || '',
    data.employeeName,
    staffCount,
    site.highwayFee || 0,
    site.distance || 0,
    site.parkingFee || 0,
    site.materialCost || 0
  ];
  await this.helpers.httpRequestWithAuthentication.call(
    this,
    'googleSheetsOAuth2Api',
    { method: 'POST', url, body: { values: [rowValues] }, json: true }
  );
  written++;
}

return [{ json: { ...data, billingWritten: written } }];

const data = $input.first().json;
const lineToken = 'Bearer YOUR_LINE_TOKEN';
const text = data.messageText || '';

// 月の解析
const now = new Date();
let year = now.getFullYear();
let month = now.getMonth() + 1;

if (text.includes('先月')) {
  month -= 1;
  if (month === 0) { month = 12; year -= 1; }
} else if (!text.includes('今月')) {
  let m = text.match(/(\d{4})年(\d{1,2})月/);
  if (m) { year = parseInt(m[1]); month = parseInt(m[2]); }
  else {
    m = text.match(/(\d{1,2})\/(\d{4})/);
    if (m) { month = parseInt(m[1]); year = parseInt(m[2]); }
    else {
      m = text.match(/(\d{1,2})月/);
      if (m) month = parseInt(m[1]);
    }
  }
}

const fileName = `請求集計_${year}年${String(month).padStart(2,'0')}月`;

const BILLING_COMPANIES = [
  '港振興業', 'トラストテクノス', '平成システム', 'FGE',
  'mtr', 'オークコミュニケーション', 'ライズ',
  '千里スカイハイツ管理組合', '菊次', 'ページ', 'G-STYLE', '梶原通信', 'LLS電気'
];

let replyMessage;

// ファイル検索
const searchRes = await this.helpers.httpRequestWithAuthentication.call(
  this, 'googleSheetsOAuth2Api', {
    method: 'GET',
    url: 'https://www.googleapis.com/drive/v3/files',
    qs: {
      q: `name='${fileName}' and mimeType='application/vnd.google-apps.spreadsheet' and '1_hE52JdvZ-Nyl-lUyKWzhFN6Lqphp9yA' in parents`,
      fields: 'files(id,name)'
    },
    json: true
  });

const files = searchRes.files || [];

if (files.length === 0) {
  replyMessage = `${year}年${month}月 請求集計\n該当ファイルがありません`;
} else {
  const ssId = files[0].id;
  const ranges = BILLING_COMPANIES.map(n => `ranges=${encodeURIComponent(n + '!A:A')}`).join('&');
  const url = `https://sheets.googleapis.com/v4/spreadsheets/${ssId}/values:batchGet?${ranges}`;

  let batchRes = { valueRanges: [] };
  try {
    batchRes = await this.helpers.httpRequestWithAuthentication.call(
      this, 'googleSheetsOAuth2Api', { method: 'GET', url, json: true });
  } catch(e) {}

  const has = [];
  const none = [];
  (batchRes.valueRanges || []).forEach((vr, i) => {
    const rows = (vr.values || []).slice(1);
    if (rows.length > 0) {
      has.push(`・${BILLING_COMPANIES[i]}（${rows.length}件）`);
    } else {
      none.push(BILLING_COMPANIES[i]);
    }
  });

  replyMessage = `${year}年${month}月 請求集計\n` +
    (has.length > 0 ? has.join('\n') : '記録なし') +
    (none.length > 0 ? `\n\n該当なし：${none.join('、')}` : '');
}

if (data.replyToken) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.line.me/v2/bot/message/reply',
    headers: { 'Authorization': lineToken, 'Content-Type': 'application/json' },
    body: { replyToken: data.replyToken, messages: [{ type: 'text', text: replyMessage }] },
    json: true
  });
}
return [{ json: { done: true, replyMessage } }];
